mapper.select:
SELECT
oc.*,
e.actual_name createUserName,
v.vehicle_number useVehicleNumber
FROM
t_etc oc
LEFT JOIN t_employee e ON e.employee_id = oc.create_user_id
LEFT JOIN t_vehicle v ON v.vehicle_id = oc.use_vehicle_id
where
    oc.deleted_flag = #{queryForm.deletedFlag}

        and oc.enterprise_id = #{queryForm.enterpriseId}


        AND (INSTR(oc.etc_no,#{queryForm.keyWords})
        or INSTR(e.actual_name,#{queryForm.keyWords})
        )


        AND oc.disabled_flag = #{queryForm.disabledFlag}



        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') >= #{queryForm.createStartTime}


        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') <= #{queryForm.createEndTime}


    ORDER BY oc.create_time DESC
